example.code:
import Testing
import Harmonize

@Suite("Architecture")
struct LayerBoundaries {
  @Test("Domain must not import UIKit")
  func domainNoUIKit() {
    Harmonize.productionCode()
      .filesIn("Sources/Domain")
      .imports()
      .assertNoneMatch { $0.name == "UIKit" }
  }

  @Test("ViewModels must end with ViewModel")
  func viewModelNaming() {
    Harmonize.productionCode()
      .filesIn("Sources/Presentation/ViewModels")
      .classes()
      .assertAllMatch { $0.name.hasSuffix("ViewModel") }
  }
}

// Documented only in README; nothing enforces it
// Architecture: Domain layer must not depend on UIKit.

// In Sources/Domain/User.swift
import UIKit  // agent added this; nothing fails
struct User {
  var avatar: UIImage?
}
